export interface Scenario {
  id: number;
  title: string;
  clientMessage: string;
  suggestedAnswer: string;
}

export const scenarios: Scenario[] = [
  { id: 1, title: "Post-mortem report", clientMessage: "Hi, following last week's outage, our management team is requesting a post-mortem report by Friday. Could you put together a summary of what happened, the root cause, and the steps we are taking to prevent it in the future?", suggestedAnswer: "Hi! Absolutely, I understand the urgency. I'll coordinate with our technical team to compile the incident details, root cause analysis, and our prevention plan. Just to confirm — do you need this in a specific format, or would a structured document covering timeline, impact, and action items work for your management?" },
  { id: 2, title: "Deadline slipped", clientMessage: "I noticed the delivery date for the new dashboard feature has slipped by two weeks. Can you explain what caused the delay and what the revised timeline looks like?", suggestedAnswer: "Thanks for flagging this. The delay was caused by unexpected complexity in the third-party integration, which required additional testing cycles. We've adjusted our sprint plan and the revised delivery is now March 28th. I'll send an updated project plan by end of day — would that work for you?" },
  { id: 3, title: "Budget increase", clientMessage: "We received your revised proposal and noticed the budget has increased by 20% compared to the original estimate. Could you walk us through what's driving that increase?", suggestedAnswer: "Thank you for bringing this up directly. The 20% increase is primarily driven by two factors: the expanded scope agreed on in last month's review, and a rise in cloud infrastructure costs. I've prepared a detailed breakdown — happy to walk you through it on a call if helpful." },
  { id: 4, title: "Feature not working", clientMessage: "The new search feature you deployed last Tuesday is still not working correctly. Our users are complaining that results are incomplete. This is affecting our business operations.", suggestedAnswer: "I sincerely apologize for the inconvenience. Our team has already identified the issue — a misconfigured indexing parameter — and a fix is being tested right now. We expect to deploy it within two hours. I'll send you a status update every 30 minutes until it's resolved." },
  { id: 5, title: "Missing documentation", clientMessage: "We've been trying to onboard new team members to the API you delivered, but the documentation is incomplete. Several endpoints are not documented at all. Can you address this urgently?", suggestedAnswer: "You're absolutely right, and I apologize for the gap. Our technical writer has been briefed and will complete the missing endpoint documentation by Thursday. I'll also schedule a walkthrough call with your team once the docs are ready to make sure everything is clear." },
  { id: 6, title: "Performance issues", clientMessage: "Since last week's deployment, the application response time has increased significantly. Some pages are taking over 5 seconds to load. This is unacceptable for our customers.", suggestedAnswer: "Thank you for reporting this. We've already started performance profiling and identified two slow database queries introduced in last week's release. Our team is optimizing them now. We expect response times back to normal by tomorrow morning, and I'll keep you updated on our progress." },
  { id: 7, title: "Request for update", clientMessage: "We haven't heard from your team in over a week regarding the migration project. Can you give us a status update? Are we still on track for the Q2 launch?", suggestedAnswer: "I apologize for the lack of communication — that's on us. The migration is currently 70% complete and we remain on track for the Q2 launch. I've just sent a detailed status report to your inbox and will set up a weekly update call going forward to ensure you're always informed." },
  { id: 8, title: "Scope change request", clientMessage: "We'd like to add real-time notifications to the platform. This wasn't in the original spec but it's become critical for our operations. How quickly can your team incorporate this?", suggestedAnswer: "Thanks for letting us know. Real-time notifications would require WebSocket integration — I'd estimate about two sprints, roughly four weeks. I'll prepare a formal change request with the scope, cost impact, and timeline by end of week. Would that work for your planning?" },
  { id: 9, title: "Data breach concern", clientMessage: "One of our employees received a suspicious email that appears to contain internal data. We are concerned there may have been a data breach on your end. Please investigate immediately.", suggestedAnswer: "I understand the seriousness of this and I'm treating it with the highest priority. Our security team has been alerted and is initiating a full audit right now. Please forward the suspicious email to our security team and don't delete anything. I'll have a preliminary assessment back to you within four hours." },
  { id: 10, title: "Invoice dispute", clientMessage: "We received your invoice for March and the amount is higher than what we agreed in the contract. Specifically, the support hours billed seem excessive. Can you justify these charges?", suggestedAnswer: "Thank you for flagging this. I'll pull the detailed support log and cross-reference it with the contract terms today. If there's a discrepancy, we'll issue a corrected invoice promptly. I'll have a full breakdown to you by end of day — would you prefer this by email or should we review it together on a call?" },
  { id: 11, title: "Team availability", clientMessage: "We have a critical product launch next month and need your team to be on standby for immediate support. Can you confirm your team's availability and response time commitments?", suggestedAnswer: "Absolutely, I understand the importance of your launch. I can assign two dedicated engineers on standby for the launch week with a 30-minute response time for critical issues. I'll prepare a formal support agreement outlining coverage hours, escalation paths, and response SLAs for your review." },
  { id: 12, title: "Third-party integration failure", clientMessage: "The payment gateway integration you built stopped processing transactions yesterday afternoon. We've lost several thousand dollars in sales. What happened and how are you fixing it?", suggestedAnswer: "I'm very sorry — this is a critical issue. The payment gateway provider updated their API without advance notice, breaking the authentication flow. Our team deployed a hotfix at 9 PM last night and transactions are processing normally now. I'll send a full incident report and work with you on contractual next steps regarding the lost revenue." },
  { id: 13, title: "Change in requirements", clientMessage: "After reviewing with our stakeholders, we need to change the user authentication approach from email/password to SSO. I know this is a significant change, but it's now a hard requirement.", suggestedAnswer: "I appreciate the transparency. SSO migration is certainly a significant change — it will affect the backend auth layer, user onboarding flow, and require security review. I'll have the team assess the full impact and prepare a revised proposal with timeline and cost adjustment within three business days." },
  { id: 14, title: "Unhappy with quality", clientMessage: "To be honest, we've been disappointed with the quality of the code delivered in the last two sprints. We found numerous bugs during testing and the code coverage is below what we agreed.", suggestedAnswer: "I appreciate you being direct, and I take this feedback seriously. The quality bar we've delivered doesn't meet our standards either. I've reviewed our QA process and I'm implementing mandatory peer code review and raising the minimum test coverage threshold starting this sprint. I'd also like to schedule a retrospective with you to ensure we're fully aligned going forward." },
  { id: 15, title: "Requesting NDA", clientMessage: "Before we share our detailed technical architecture, we need a mutual NDA signed by your company. Can you facilitate this quickly as it's blocking our project kickoff?", suggestedAnswer: "Of course — protecting both parties' confidential information is important. I'll connect you directly with our legal team today and they can typically turn around a mutual NDA within 24-48 hours. Could you send your standard NDA template, or would you prefer to use ours? Either way, we'll prioritize this to unblock the kickoff." },
  { id: 16, title: "Slow hiring", clientMessage: "You committed to having a full team of five engineers in place by now, but I see only three on the project. When will the other two join, and how is this affecting our timeline?", suggestedAnswer: "You're right to raise this. We've had two offer rejections due to a competitive market, which has delayed our full team assembly. We have strong candidates in final interviews now and expect both engineers to start by the 15th. I've assessed the impact — it adds approximately one week to the first milestone, and I'll revise the timeline document today." },
  { id: 17, title: "Request for demo", clientMessage: "Our board is meeting next Friday and they want to see a live demo of the product so far. Can your team prepare and lead a 30-minute demonstration?", suggestedAnswer: "Absolutely, we'd be happy to showcase what we've built. Could you share the topics or user flows the board is most interested in? That will help us tailor the demo for maximum impact. I'll also prepare a brief deck covering the technical highlights and roadmap. Would a rehearsal call on Thursday work for you?" },
  { id: 18, title: "License compliance", clientMessage: "Our legal team has flagged that one of the open-source libraries you're using in our project has a GPL license, which could create issues with our proprietary software. Please clarify.", suggestedAnswer: "Thank you for catching this. Our team has reviewed the flagged library and you're correct — it carries a GPL-2.0 license. We've identified a compatible MIT-licensed alternative that provides the same functionality. We'll replace it in the next sprint with no impact on existing features. I'll document the change and send your legal team a full dependency license report." },
  { id: 19, title: "Urgent hotfix needed", clientMessage: "There is a critical bug in production that is preventing all users from logging in. This has been happening for the past hour and is our top priority. We need this fixed NOW.", suggestedAnswer: "I'm on it immediately. I've declared a P1 incident and our on-call engineer is working on it right now. We've identified the issue — a failed session token migration script — and the fix is being tested. ETA to resolution is 20 minutes. I'll keep you updated every 15 minutes until users can log in again." },
  { id: 20, title: "Contract renewal", clientMessage: "Our current engagement contract expires at end of this month. We're happy with the work overall, but before renewing we'd like to discuss the commercial terms and explore options for a longer commitment.", suggestedAnswer: "Thank you — it's great to hear you're satisfied with the collaboration. I'd love to sit down and discuss the renewal. We have a few flexible commercial models including a 12-month retainer with reduced rates, or a time-and-materials arrangement. I'll prepare a comparison sheet for your review and suggest a call early next week — does Monday work?" },
  { id: 21, title: "Missing meeting", clientMessage: "You were supposed to attend our product review meeting this morning and we didn't see you on the call. This is the third time this has happened. We need reliability from your team.", suggestedAnswer: "I sincerely apologize — there was a scheduling miscommunication on our end and that's not an excuse for a recurring issue. I've reviewed our calendar management process and have appointed a backup attendee going forward. I'd like to reschedule the product review at your earliest convenience and ensure this doesn't happen again." },
  { id: 22, title: "API rate limiting", clientMessage: "We're getting rate limit errors from the API integration you built. This is causing data sync failures during peak hours. We need a solution that can handle our traffic volume.", suggestedAnswer: "Thanks for the detailed description. The current implementation doesn't include request queuing or exponential backoff, which is causing the burst failures. I'll have the team implement a proper rate limit handler with queue management this week. In the interim, we can request a rate limit increase from the provider if you'd like me to pursue that in parallel." },
  { id: 23, title: "Security audit findings", clientMessage: "Our security team has completed an audit and found several vulnerabilities in the application, including two rated high severity. We need these addressed before we can go to production.", suggestedAnswer: "Thank you for sharing the audit report. I've reviewed all findings and the two high-severity items — an SQL injection risk and an unvalidated redirect — will be patched by end of this week. The medium and low items will be addressed in the following sprint. I'll send you a formal remediation plan with timelines by tomorrow." },
  { id: 24, title: "Competitor comparison", clientMessage: "We've been evaluating a competing vendor who claims they can deliver the same functionality in half the time for 30% less cost. Can you help us understand the value of continuing with your team?", suggestedAnswer: "I appreciate you being transparent. Competitive pricing matters, and I'd like to understand exactly what's being compared. Speed and cost differences often reflect trade-offs in architecture quality, testing, or long-term maintainability. I'd be happy to schedule a technical deep-dive where we walk through our approach, and if there are areas where we can optimize costs without compromising quality, I want to find them." },
  { id: 25, title: "Data privacy question", clientMessage: "We have clients in the EU and need to ensure your solution is fully GDPR compliant. Can you provide documentation of your data processing practices and where user data is stored?", suggestedAnswer: "GDPR compliance is critical for your EU users. Our infrastructure is hosted in EU data centers in Frankfurt, and we have a Data Processing Agreement template ready. Our DPO can also provide a full record of processing activities. I'll have the compliance documentation package sent to your legal team by Friday — would that timeline work?" },
  { id: 26, title: "Wrong environment deployed", clientMessage: "Your team accidentally deployed a test build to our production environment this afternoon. This caused several hours of incorrect behavior that affected real customers. How did this happen?", suggestedAnswer: "I'm deeply sorry for this — it should never have happened. A manual deployment script error caused the wrong build to be promoted to production. We've restored the correct version and customers are no longer affected. I'm implementing mandatory environment confirmation gates in our deployment pipeline today. I'll send a full incident report and preventive measures within 24 hours." },
  { id: 27, title: "Support response too slow", clientMessage: "We've submitted three support tickets in the past week and the average response time has been over 48 hours. Our SLA states a 4-hour response for critical issues. This is a breach.", suggestedAnswer: "You're absolutely right, and I take full responsibility for this SLA breach. I've reviewed the tickets — two were misclassified as low priority, which caused the delay. I'm correcting the ticket priorities now and escalating them personally. I'll also review our triage process to prevent mis-classification. I'll report back on the remediation plan within the hour." },
  { id: 28, title: "Requesting source code", clientMessage: "Per our contract, we have rights to the source code of the deliverables. We'd like to receive the full repository access by end of this week as we need it for an internal audit.", suggestedAnswer: "Of course — that's your right under the contract. I'll set up your team's access to the repository today and send the invite links within the hour. I'll also ensure all branches, tags, and documentation are clean and organized for your audit. If you need a technical walkthrough of the codebase structure, I'm happy to arrange that too." },
  { id: 29, title: "Scope creep dispute", clientMessage: "You've submitted a change request for additional hours, but our project manager believes the features in question are part of the original agreed scope. We need to resolve this disagreement.", suggestedAnswer: "Thank you for raising this directly. Scope alignment is important and I want to resolve this fairly. I'll prepare a side-by-side comparison of the original scope document and the features in question, with specific references to the requirements. I suggest we review this together on a call — if the features are within original scope, we'll absorb the hours. If not, the change request stands." },
  { id: 30, title: "Technology stack question", clientMessage: "We're concerned about your choice to use a relatively new framework for our core system. Our team lacks expertise in it and we're worried about long-term maintainability. Can you justify this decision?", suggestedAnswer: "That's a very valid concern and I should have discussed this with you earlier. The framework was chosen for its performance characteristics and strong community support, but maintainability is equally important. I'll prepare a technical justification document and also assess whether a more widely-known alternative would meet our requirements without significant trade-offs. Would a technical review meeting with your team help?" },
  { id: 31, title: "Requesting refund", clientMessage: "Given the delays and quality issues we've experienced over the past two months, we would like to request a partial refund for services that were not delivered as agreed.", suggestedAnswer: "I understand your frustration, and I want to acknowledge that we have not consistently met the standards you deserve. I'll review the specific items against our contract and discuss with our commercial team. We want to reach a fair resolution — could you send a summary of the specific deliverables and issues? I'll respond within three business days with our proposal." },
  { id: 32, title: "Requesting SLA upgrade", clientMessage: "With our upcoming product launch, we need 24/7 support coverage and 99.9% uptime guarantee for at least three months. Can you offer this and at what cost?", suggestedAnswer: "We can absolutely offer that. Our premium SLA tier includes 24/7 on-call support with 15-minute critical issue response and infrastructure monitoring with 99.95% uptime guarantee. I'll prepare a commercial proposal with detailed terms and pricing by tomorrow. Do you also need a dedicated account manager during the launch period?" },
  { id: 33, title: "Access permission denied", clientMessage: "Your developers have requested admin access to our AWS production account, but our security policy doesn't allow this. How can we work around this without compromising our security standards?", suggestedAnswer: "Completely understood — admin access to production should always be tightly controlled. We can work with a scoped IAM role that grants only the minimum permissions needed for deployment and monitoring, with all actions logged in CloudTrail. I'll prepare a detailed IAM policy document for your security team to review and approve. Would that approach work?" },
  { id: 34, title: "Delayed UAT feedback", clientMessage: "We completed UAT three weeks ago and submitted our feedback. We haven't seen any of the fixes deployed yet. This is blocking our go-live date. What's the status?", suggestedAnswer: "I apologize for the delay — this should have been communicated proactively. Of the 23 UAT items, 18 are resolved and deployed. The remaining five require a UX design change which is in review. I'm prioritizing these for the next release on Thursday. I'll send a UAT resolution tracker today with status on each item and the projected completion dates." },
  { id: 35, title: "Compliance certification needed", clientMessage: "Our enterprise clients require that all technology vendors hold ISO 27001 certification. Do you hold this certification? If not, is there an alternative compliance framework you can demonstrate?", suggestedAnswer: "We currently hold SOC 2 Type II certification and are actively pursuing ISO 27001, with expected completion by Q3. Many enterprise clients accept SOC 2 as an equivalent standard. I'll send our SOC 2 report and our ISO 27001 roadmap today. If your clients have specific requirements, I'd be happy to arrange a conversation between our compliance teams." },
  { id: 36, title: "Staff turnover concern", clientMessage: "We've noticed that two key engineers from our project team have left your company in the past month. We're concerned about knowledge loss and continuity. How are you managing this?", suggestedAnswer: "I appreciate you raising this directly. We have taken immediate steps: comprehensive knowledge transfer sessions were completed before both engineers departed, and their replacements have been ramped up on your codebase. I've also ensured that all critical documentation is updated and centralized. I'd like to schedule an introduction call with the new engineers at your convenience." },
  { id: 37, title: "Wrong data in report", clientMessage: "The financial report your system generated for Q1 has incorrect totals. The numbers don't match our accounting records by about 12%. This could have caused a serious issue if we hadn't caught it.", suggestedAnswer: "Thank you for catching this before it caused further issues. Our team is investigating the discrepancy now. I suspect there's a currency conversion rounding error in the aggregation logic. I'll have a root cause analysis and corrected report to you within 24 hours, and we'll implement additional validation checks to prevent this from happening again." },
  { id: 38, title: "Requesting knowledge transfer", clientMessage: "As our contract comes to an end, we need a comprehensive knowledge transfer to our internal team. What does your knowledge transfer process look like and how long will it take?", suggestedAnswer: "Great question — a smooth handover is a priority for us too. Our standard knowledge transfer includes documented architecture overview, codebase walkthrough sessions, runbook for operations, and a Q&A period for your team. For a project of this size, I'd estimate four weeks. I'll prepare a knowledge transfer plan this week — would it be helpful to start two months before the contract end?" },
  { id: 39, title: "Urgent feature request", clientMessage: "We just found out our biggest client requires a specific report format by next Thursday or they will cancel their subscription. We need you to build this urgently. Can you do it?", suggestedAnswer: "I understand the urgency — let's make this happen. Could you share the exact report format required? I'll assess the technical complexity today and give you a realistic estimate by end of day. If it's achievable by Thursday, we'll prioritize it immediately. If not, I'll also suggest any interim solutions we can offer to keep your client satisfied while we complete it." },
  { id: 40, title: "Infrastructure cost spike", clientMessage: "Our AWS bill this month was 3x higher than usual. We believe this is related to the infrastructure changes your team made last sprint. Can you investigate and explain?", suggestedAnswer: "I've already started investigating. Initial review shows that a new data processing job deployed last sprint was not configured with auto-scaling limits, causing excessive instance usage. The job has been throttled and I expect costs to normalize this week. I'll send a full cost analysis and the configuration changes we're implementing to prevent this going forward." },
  { id: 41, title: "Competitor poaching concern", clientMessage: "We've heard that your team has been approached by our main competitor to do similar work for them. We have a confidentiality clause in our contract and want to ensure our IP is protected.", suggestedAnswer: "I take this very seriously. Our contract's confidentiality and non-compete provisions are clear and we fully comply with them. I can confirm we have not disclosed any confidential information from your engagement. I'll have our legal team review the relevant contract clauses and send you a formal written confirmation of our compliance commitments today." },
  { id: 42, title: "Testing environment broken", clientMessage: "The staging environment has been broken since Monday and our QA team hasn't been able to test anything for three days. This is causing a bottleneck in our release process.", suggestedAnswer: "I apologize for this — three days without a working staging environment is a serious disruption. Our DevOps engineer has been assigned as the sole focus on this. The issue is a misconfigured SSL certificate after the domain migration. It will be fixed within the next two hours. I'll set up a status check meeting every morning going forward to catch environment issues faster." },
  { id: 43, title: "Missing backup strategy", clientMessage: "During a recent review, our internal team found that your production setup doesn't include automated daily backups. This is a major risk. Why wasn't this implemented?", suggestedAnswer: "You're absolutely right — automated backups should have been in place from day one and I apologize for this gap. Our team is implementing automated daily backups with seven-day retention starting today. We'll also add backup restoration drills to our quarterly process. I'll send a full backup and disaster recovery plan document for your review by tomorrow." },
  { id: 44, title: "Requesting detailed timeline", clientMessage: "We're planning internal resources around your delivery schedule and we need a detailed week-by-week timeline for the next three months. Can you provide this by end of week?", suggestedAnswer: "Absolutely. I'll prepare a detailed Gantt-style timeline covering all sprints, milestones, and dependencies for the next 12 weeks. I'll include key deliverables, review gates, and the resource assignments. I'll have the first draft ready for your review by Thursday — should I include capacity risks and mitigation plans as well?" },
  { id: 45, title: "Multi-language support", clientMessage: "We're expanding to Southeast Asian markets and need the application to support Vietnamese, Thai, and Indonesian. What's the effort involved and when can it be ready?", suggestedAnswer: "Multi-language support is definitely feasible. If we implement it properly using an i18n framework, adding new languages later becomes straightforward. For three languages, I'd estimate 6-8 weeks including UI adjustments for different text lengths. The translation content would need to come from your side or a professional translation service. I'll prepare a detailed proposal with options and timelines this week." },
  { id: 46, title: "Mobile app crash reports", clientMessage: "We've been receiving complaints from users that the mobile app crashes on startup on Android 10 devices. This is affecting about 15% of our user base. Can you look into this?", suggestedAnswer: "Thanks for the detailed report. Android 10 introduced some permission model changes that may be causing this. Our mobile team is reproducing the crash on a device emulator right now. I'll have a diagnosis within two hours and a hotfix deployed within 24 hours once confirmed. I'll also improve our device coverage in CI to catch these earlier." },
  { id: 47, title: "Requesting penalty clause", clientMessage: "We'd like to add a penalty clause to our contract for future delays — a 2% fee per day for any deliverables that miss agreed deadlines. Is your team willing to accept this?", suggestedAnswer: "I appreciate the direct approach. I'm open to discussing accountability mechanisms in the contract. A 2% daily penalty is quite steep — I'd suggest we explore a tiered structure, such as service credits for minor delays and penalty clauses only for material breaches. I'll have our legal team prepare a counter-proposal that protects both parties' interests and reflects realistic project dynamics." },
  { id: 48, title: "Data migration request", clientMessage: "We need to migrate approximately 5 million records from our legacy system to the new platform before go-live. Can you take ownership of this and ensure data integrity?", suggestedAnswer: "We can absolutely take ownership of the data migration. For 5 million records, I'd recommend a phased migration approach with data validation checks at each stage. I'll prepare a migration plan covering data mapping, validation scripts, rollback procedures, and a dry-run schedule. Typically this process takes 4-6 weeks — I'll confirm after reviewing your data structure." },
  { id: 49, title: "UI consistency complaint", clientMessage: "Our design team has reviewed the latest screens and there are significant inconsistencies in typography, spacing, and color usage across different sections of the app. This doesn't match our design system.", suggestedAnswer: "Thank you for the detailed feedback. Our front-end team hasn't been consistently referencing the design system tokens — I'll correct this immediately. I'm scheduling a design review session between our engineers and your design team this week to align on the standards. I'll also integrate design system linting into our build process to catch inconsistencies automatically going forward." },
  { id: 50, title: "Requesting progress meeting", clientMessage: "We'd like to schedule a monthly steering committee meeting with your senior leadership and ours to review progress, risks, and strategic alignment. Can you organize this?", suggestedAnswer: "That's a great idea and I'd welcome the increased visibility at the leadership level. I'll coordinate with our CTO to set up a standing monthly steering committee meeting. I'll prepare a proposal for the agenda format, attendees, and reporting template for your review. Would the first meeting next month work, or would you prefer to start sooner?" },
  { id: 51, title: "API versioning concern", clientMessage: "We've noticed that you've released a new version of the API without proper notice, and our integrations have broken as a result. We need a formal API versioning and deprecation policy.", suggestedAnswer: "I sincerely apologize for the disruption. You're right — any breaking API changes must go through a formal deprecation process with at least 90 days notice. I'm restoring backward compatibility for your current integration today, and I will formalize and share our API versioning policy this week to ensure this never happens again." },
  { id: 52, title: "Requesting case study", clientMessage: "Would you be willing to write a case study about your work with us? We'd like to see it before it's published, and we want to ensure our company name is not mentioned without approval.", suggestedAnswer: "We'd love to create a case study — your project has some great results worth highlighting. Absolutely, we'll share the draft for your review and approval before any publication, and we would never name your company without explicit written consent. I'll prepare a draft outline first for you to review the angle and content. Would it be okay to proceed under a non-disclosure basis for now?" },
  { id: 53, title: "Downtime notification", clientMessage: "We need at least 72 hours advance notice before any scheduled maintenance that could cause downtime. We didn't receive any notice for last weekend's maintenance window.", suggestedAnswer: "You're completely right, and I apologize for the oversight. Our standard notification procedure wasn't followed this time due to an urgent security patch that needed immediate deployment. I've updated our communication process to require advance notice even in urgent cases unless it's an emergency security issue. I'll send you our updated maintenance notification policy today." },
  { id: 54, title: "Missing audit log", clientMessage: "During a compliance review, we found that user actions in the admin panel are not being logged. We require a complete audit trail for regulatory compliance. Why was this not built in from the start?", suggestedAnswer: "This is an important oversight and I take responsibility for it. Audit logging for admin actions is a standard compliance requirement that should have been included in the initial build. Our team will implement comprehensive audit logging this sprint, covering all admin actions with timestamps, user IDs, and IP addresses. I'll also provide a compliance checklist review to identify any other gaps." },
  { id: 55, title: "Vendor dependency risk", clientMessage: "We're concerned that your architecture relies heavily on a single third-party vendor that could become a single point of failure. What's your vendor risk management strategy?", suggestedAnswer: "That's a legitimate architectural concern. The current design does have a dependency concentration that we should address. I'll prepare a vendor risk analysis and propose a decoupling strategy with fallback mechanisms. For the most critical dependencies, we can introduce abstraction layers that allow vendor switching without application changes. I'll have a proposal ready within two weeks." },
  { id: 56, title: "User acceptance testing plan", clientMessage: "We're about to start UAT for Phase 2 and we need a comprehensive test plan from your team covering all the new features, edge cases, and regression scenarios.", suggestedAnswer: "Great timing — we're already preparing the UAT documentation. I'll have a comprehensive test plan to you by end of this week including test cases for all new features, edge cases, and a regression suite. I'll also set up a shared test management platform so your team can track results and log issues directly. Shall I arrange a UAT kickoff meeting for next Monday?" },
  { id: 57, title: "Competitor product analysis", clientMessage: "We need your technical opinion on a competing product that's gaining traction in our market. Can you analyze its architecture and features and give us a detailed technical assessment?", suggestedAnswer: "That's a great strategic request. I can do a technical teardown of the competitor product based on publicly available information — their API docs, technical blog posts, and product announcements. I should note this analysis will be limited to what's publicly accessible, but it should give you a solid technical perspective. I'll have a report ready within one week." },
  { id: 58, title: "Overtime billing", clientMessage: "Your last invoice includes 40 hours of overtime billed at 1.5x rate. We were never informed that overtime would be needed or that additional charges would apply. This is surprising.", suggestedAnswer: "You're right to question this — we should have flagged the overtime before it was incurred. The hours were necessary to meet the agreed milestone, but the billing impact should have been discussed with you in advance. I'll waive the overtime premium for this invoice as a goodwill gesture and implement a process where any projected overtime requires your approval first." },
  { id: 59, title: "Requirements clarification", clientMessage: "The requirements document you've been working from is outdated. Our product team has been updating the requirements in Confluence but it seems your team isn't using the latest version. This has wasted significant development effort.", suggestedAnswer: "That's a serious process breakdown and I apologize. We've been working from the initial signed-off document, not the live Confluence version. Going forward, I'll assign a dedicated requirements coordinator who will review Confluence daily and surface any changes before sprint planning. I'd also like to discuss a formal change request process so updates are tracked and approved before development begins." },
  { id: 60, title: "Requesting pilot extension", clientMessage: "We've been in a paid pilot for 3 months and we're not yet confident enough to commit to a full contract. Can you offer a 2-month extension of the pilot terms while we complete our evaluation?", suggestedAnswer: "I understand — you want to feel fully confident before committing. I'm happy to offer a 2-month pilot extension at the same terms. I'd also like to understand what specific criteria would help you make the decision, so we can focus on demonstrating those areas clearly during the extension. Would you be able to share your evaluation framework?" },
  { id: 61, title: "CI/CD pipeline broken", clientMessage: "Your team's recent changes broke our CI/CD pipeline and none of our code can be deployed. The QA team is blocked and we're 3 days from a release. This is critical.", suggestedAnswer: "I'm on this immediately. A dependency version conflict introduced yesterday is causing the pipeline failure. Our DevOps engineer is rolling back that change right now. The pipeline should be restored within the next hour. I'm also adding a pipeline validation step to our PR checklist to prevent this from happening again. I'll confirm once deployments are running." },
  { id: 62, title: "Requesting architecture review", clientMessage: "Before we approve the next phase of development, our CTO wants an architecture review from your team. Can you prepare and present the technical architecture for Phase 2?", suggestedAnswer: "Absolutely — a pre-development architecture review is excellent practice. I'll prepare a comprehensive architecture document covering system design, data flows, technology choices, scalability approach, and security considerations for Phase 2. I'll also prepare a presentation deck for the CTO review. Would a 2-hour review session in two weeks work, or does your CTO have an earlier preference?" },
  { id: 63, title: "SEO performance drop", clientMessage: "Since the website redesign your team delivered, our organic search rankings have dropped significantly. We're losing about 30% of our search traffic. Is there something in the new implementation causing this?", suggestedAnswer: "That's a significant impact and we need to investigate urgently. The most common culprits after a redesign are changed URL structures without proper redirects, missing meta tags, or slower page load times. I'll run a technical SEO audit today and have findings to you by tomorrow. If the issue is in our implementation, we'll fix it at no additional cost." },
  { id: 64, title: "Requesting SLA report", clientMessage: "Per our contract, you're supposed to provide monthly SLA compliance reports. We haven't received one in four months. Can you send us the reports for June through September immediately?", suggestedAnswer: "I apologize for the oversight — this is a contractual commitment we haven't met. I'll have all four reports prepared and sent to you by tomorrow. Going forward, I'm setting up an automated monthly report that will be delivered on the first business day of each month. I'd also like to add a quarterly service review call to ensure we're maintaining transparency on all SLA metrics." },
  { id: 65, title: "Requesting code review", clientMessage: "Before we accept the Phase 1 deliverables, we'd like to have an independent code review conducted. We want to ensure the code quality meets our standards. Is this acceptable?", suggestedAnswer: "Absolutely, we welcome an independent code review — it's a healthy practice and demonstrates our confidence in the work. I'll prepare a code access package with documentation for the reviewers. If you need recommendations for independent reviewers, I can suggest a few well-regarded consultancies. Just let me know your preferred process and timeline." },
  { id: 66, title: "Missing error handling", clientMessage: "During testing, we found that the application shows raw error messages and stack traces to end users when something goes wrong. This is both a security risk and a poor user experience.", suggestedAnswer: "You're absolutely right on both counts — exposing raw errors to users is unacceptable. This is a straightforward but important fix. Our team will implement a global error handler that logs errors server-side and displays friendly, user-appropriate messages instead. This will be in the next release on Friday. I'll also review all API error responses to ensure they follow the same standard." },
  { id: 67, title: "Requesting staff augmentation", clientMessage: "We have an upcoming peak period and need three additional mid-level developers to work directly with our internal team for six months. Can you provide staff augmentation?", suggestedAnswer: "Yes, staff augmentation is something we offer. I can provide three mid-level developers with the skills you need. Typical onboarding for a new team is two weeks, so if you need them by the 1st, we'd want to start the selection process this week. Can you share the tech stack requirements and any specific domain knowledge needed? I'll shortlist candidates for your team to interview." },
  { id: 68, title: "Conflicting priorities", clientMessage: "It seems like your team is splitting their attention between our project and another client. We're not getting the full commitment we expected. We'd like dedicated resources for our engagement.", suggestedAnswer: "Thank you for raising this directly. I want to be transparent: our current assignment model does have some engineers shared, which has impacted your project's momentum. I'm restructuring the team immediately to give you three dedicated engineers. I'll send you an updated resource allocation plan today and I'm committed to ensuring this doesn't affect your delivery timelines." },
  { id: 69, title: "Legal hold on data", clientMessage: "We need to put a legal hold on all data related to our project due to a potential litigation. Can you ensure no data is deleted or modified until further notice?", suggestedAnswer: "Understood — I'm treating this as urgent. I've immediately frozen all deletion and archiving processes for your project data. I'll also disable any automated data cleanup scripts. Our legal team will be in touch with your counsel to formalize the hold protocol. Please send any specific instructions from your legal team and we'll comply fully." },
  { id: 70, title: "Requesting performance optimization", clientMessage: "With our user base growing 3x in the last quarter, we're starting to see performance degradation. We need a performance optimization plan before we hit critical thresholds.", suggestedAnswer: "Great timing to address this proactively. I'll kick off a performance assessment this week covering database query optimization, caching strategy, CDN configuration, and infrastructure scaling options. Based on your growth trajectory, I'll model the performance thresholds and recommend a phased optimization roadmap. I'll have the initial assessment back to you within two weeks." },
  { id: 71, title: "Requesting disaster recovery plan", clientMessage: "Our risk management team requires a documented disaster recovery plan covering your systems. We need RTO and RPO targets and evidence that these can be met.", suggestedAnswer: "A documented DR plan is essential and we take this seriously. Our current setup supports an RTO of 4 hours and RPO of 1 hour based on our backup frequency. I'll formalize this into a comprehensive DR plan document including runbooks, escalation procedures, and test schedules. I'll also propose a quarterly DR drill to validate the plan in practice." },
  { id: 72, title: "Inconsistent naming conventions", clientMessage: "During our code review, we found that your team uses inconsistent naming conventions across the codebase — some files use camelCase, others use snake_case. This will make maintenance difficult.", suggestedAnswer: "You're right — naming consistency is important for maintainability. The inconsistency accumulated across several developers working on the project without a unified standard. I'll establish an official naming convention document this week and run a cleanup pass on the existing code. Going forward, this will be enforced through our linting configuration." },
  { id: 73, title: "Requesting referral", clientMessage: "We're very pleased with your work and would like to refer you to a partner company. However, we'd need you to sign a referral agreement first. Is that something you're open to?", suggestedAnswer: "We're really glad to hear you're pleased with the work — that means a great deal. We'd be very open to a referral arrangement. I'll pass the referral agreement to our legal team to review and we can likely finalize it quickly. Could you share the agreement terms? And thank you sincerely for the confidence — we look forward to being introduced to your partner." },
  { id: 74, title: "Unexpected production change", clientMessage: "We noticed a change was made to our production database schema without going through the change management process. Who authorized this and why did it happen?", suggestedAnswer: "I've investigated this already. A developer made a direct schema change to fix an urgent data integrity issue but bypassed the change management process — which is a clear policy violation. I've spoken with the engineer and am reinforcing the change management protocol with the entire team. Going forward, all production changes require a ticket, review, and approval regardless of urgency. I'll send you a full incident report today." },
  { id: 75, title: "Request for white-label option", clientMessage: "We're interested in white-labeling your solution to resell to our clients. What would that arrangement look like commercially and technically?", suggestedAnswer: "A white-label arrangement is something we can discuss. Technically, we can remove our branding and apply your brand guidelines throughout the product. Commercially, white-label licensing typically involves a per-seat or revenue-share model. I'll prepare a white-label proposal with technical specs and commercial options for your review. Would an exploratory call this week make sense before we get into specifics?" },
  { id: 76, title: "Data retention policy question", clientMessage: "How long do you retain client data after contract termination? We need to ensure our data is deleted within 30 days of contract end per our company policy.", suggestedAnswer: "Our standard data retention policy is 90 days post-contract for recovery purposes, but we can absolutely accommodate a 30-day deletion requirement. I'll add this as a contract amendment and our data team will confirm the specific deletion procedures. You'll also receive a written confirmation when the deletion is completed. Shall I prepare the amendment for your review?" },
  { id: 77, title: "Failing health checks", clientMessage: "Our monitoring system is showing health check failures on two of the microservices your team manages. The failures have been intermittent over the past 48 hours and we're concerned.", suggestedAnswer: "Thanks for the alert — I'm looking at the health check logs now. The intermittent failures appear to be caused by memory pressure during peak traffic. The services are recovering automatically, but the root cause needs to be addressed. I'm increasing memory allocation as an immediate measure and will investigate the underlying memory leak. I'll update you by end of day today." },
  { id: 78, title: "Requesting faster iterations", clientMessage: "We need to move faster. Our business is in a competitive market and two-week sprints feel too slow. Can your team do weekly releases without sacrificing quality?", suggestedAnswer: "I appreciate the urgency. Moving to weekly releases is achievable with the right guardrails. We'd need to invest in additional automated testing coverage and streamline our deployment pipeline. The trade-off is that the first few weeks may have a slightly higher bug rate as we stabilize the process. I'll prepare a plan for the transition and we can target weekly releases within four weeks if you'd like to proceed." },
  { id: 79, title: "Team introduction request", clientMessage: "We'd like to meet all the team members working on our project. Can you organize a virtual introduction session where each person introduces their role and responsibilities?", suggestedAnswer: "Great idea — a team introduction helps build trust and communication. I'll organize a 45-minute virtual kickoff session where each team member introduces themselves, their role, and their primary focus area. I'll also prepare a team org chart and contact directory to send in advance. Would next week work, and do you have any preference for time zones?" },
  { id: 80, title: "Requesting test results", clientMessage: "Before we accept the deliverables for Phase 2, we need the full test results including unit test coverage reports, integration test results, and performance test results.", suggestedAnswer: "Absolutely — test documentation is part of our standard acceptance package. I'll compile the full test report including unit test coverage (currently at 78%), integration test results, and the performance benchmarks we ran. I'll have everything ready for your review by Thursday. I'll also include a summary of any known open issues and their planned resolution timeline." },
  { id: 81, title: "Requesting faster response", clientMessage: "When we send emails to your team, we often wait 24-48 hours for a response. In a fast-moving project, this is too slow. We need a more responsive communication channel.", suggestedAnswer: "That response time is too slow and I agree with you. I'll set up a shared Slack channel for our teams as the primary communication channel, with a commitment to respond to messages within two hours during business hours. For urgent issues, I'll provide a direct phone number for escalation. I'll have this set up by tomorrow morning." },
  { id: 82, title: "Inconsistent progress reporting", clientMessage: "The status reports we receive vary widely in format and detail from week to week. We need standardized reporting so we can compare progress across periods effectively.", suggestedAnswer: "Absolutely fair feedback — consistency in reporting is important for your planning. I'll create a standardized weekly report template covering sprint progress, blockers, risks, metrics, and next steps. I'll use it starting from this Friday's report. I'll also share the template with you in advance so you can suggest any additions that would be valuable for your team." },
  { id: 83, title: "Requesting training materials", clientMessage: "Our operations team needs to maintain the system after handover. Can you provide comprehensive training materials and conduct training sessions before the end of the contract?", suggestedAnswer: "Definitely — a well-prepared operations team is essential for long-term success. I'll prepare training materials including system architecture overview, operational runbooks, common troubleshooting guides, and admin user guides. I'll also plan three structured training sessions: system overview, day-to-day operations, and incident response. I'll have the materials ready four weeks before handover." },
  { id: 84, title: "Third-party vendor recommendation", clientMessage: "We need to choose an email service provider for transactional emails. Can your team evaluate options and recommend the best fit for our scale and budget?", suggestedAnswer: "Happy to help with the evaluation. I'll compare the main options — SendGrid, Mailgun, Amazon SES, and Postmark — against your requirements for deliverability, cost, developer experience, and analytics. I'll prepare a comparison matrix with a recommendation and the rationale. Do you have a monthly email volume estimate and budget range I can factor in?" },
  { id: 85, title: "Lack of transparency", clientMessage: "We feel like we're not getting full visibility into the project's technical challenges. Issues seem to be handled internally without keeping us informed. We'd like more transparency.", suggestedAnswer: "Your feedback is important and fair. We've been trying to resolve issues before escalating, but in doing so we've left you in the dark on challenges that affect your planning. Going forward, I'll include a risks and issues section in every weekly report and flag anything with potential timeline impact immediately — even if we don't yet have a solution. Would you also like to be included in our sprint retrospectives?" },
  { id: 86, title: "Requesting extended warranty", clientMessage: "Our standard contract includes 90 days warranty. We'd like to extend this to 12 months for critical components. What would that cost?", suggestedAnswer: "An extended warranty is definitely possible. For 12 months on critical components, I'd propose a maintenance and warranty package that includes bug fixing, security patches, and minor updates. I'll prepare commercial options — a fixed annual fee or a per-incident model — and share them by end of week. Would it also make sense to include performance monitoring during the extended period?" },
  { id: 87, title: "Cross-border data transfer", clientMessage: "Our legal team has flagged that some user data is being transferred across borders in ways that may not comply with local data protection laws. Can you provide details of all data flows?", suggestedAnswer: "This is a serious compliance concern and I'll treat it with urgency. I'll prepare a full data flow diagram showing where all user data is processed, stored, and transferred, including cross-border flows. Our data protection team will also review this against the relevant regulations and identify any transfers that require remediation. I'll have the initial report to your legal team within five business days." },
  { id: 88, title: "Requesting faster onboarding", clientMessage: "We've been waiting four weeks for our new system to be onboarded. Each delay is costing us productivity. What's blocking the onboarding and when will it be complete?", suggestedAnswer: "I understand the frustration — a four-week onboarding delay is too long. The main blockers have been waiting on environment credentials from your IT team and unresolved network firewall rules. I've just confirmed those are now resolved. With those unblocked, I'm scheduling a dedicated onboarding session for the day after tomorrow and estimate we'll be fully live within three business days." },
  { id: 89, title: "Requesting scalability assessment", clientMessage: "We're planning a marketing campaign that could bring 10x normal traffic in a 48-hour window. Can you assess whether the current infrastructure can handle this and prepare a scaling plan?", suggestedAnswer: "Great to know about this in advance — that's exactly the kind of event we need to prepare for. I'll run a load test simulating the 10x traffic scenario this week and prepare a scaling plan covering auto-scaling configuration, CDN optimization, and database read replicas if needed. I'll also prepare a pre-campaign checklist and post-campaign monitoring plan. When is the campaign launch date?" },
  { id: 90, title: "Requesting API documentation", clientMessage: "Our mobile development team needs comprehensive API documentation before they can start integrating with your backend. When can you have this ready?", suggestedAnswer: "The API documentation is a priority — I'll have it ready by end of this week. I'll use OpenAPI/Swagger format, which will include all endpoints, request/response schemas, authentication details, and code examples in three languages. I'll also set up an interactive API explorer environment your team can use for testing. Would it help to schedule a technical walkthrough once the docs are delivered?" },
  { id: 91, title: "Requesting milestone-based billing", clientMessage: "We'd prefer to switch from monthly billing to milestone-based billing. This gives us better budget control and aligns payment with delivery. Is this something you can accommodate?", suggestedAnswer: "Milestone-based billing works well for both parties. I'll draft a revised billing schedule tied to the key project milestones we have planned. For each milestone, I'll define the acceptance criteria so we're aligned on what constitutes completion. I'll have the proposal ready by Friday — I'd suggest we also review the milestone definitions together to ensure they're clear and realistic." },
  { id: 92, title: "Requesting pen test", clientMessage: "Before we launch, our security policy requires a penetration test by an independent third party. Can you facilitate this and ensure the findings are addressed before launch?", suggestedAnswer: "Absolutely — a pre-launch pen test is a best practice we support. I can recommend two reputable independent security firms we've worked with before, or you can bring your own tester. We'll provide them with the necessary system access and documentation. Once findings are received, we'll triage them by severity and address critical and high findings before launch. I'll coordinate the scheduling this week." },
  { id: 93, title: "Feature parity complaint", clientMessage: "The web version and mobile app have inconsistent features. Several capabilities available on web are missing from mobile. Our users are frustrated by the inconsistency.", suggestedAnswer: "You're right — feature parity between web and mobile should have been managed more tightly. I'll prepare a gap analysis comparing all features across platforms by end of this week. I'll then prioritize the highest-impact missing mobile features for the next two sprints. I'll also propose a process going forward where new features are always planned for both platforms simultaneously." },
  { id: 94, title: "Requesting executive briefing", clientMessage: "Our CEO wants a briefing on the current state of the project, key risks, and recommended path forward. Can you prepare a concise executive presentation?", suggestedAnswer: "Happy to prepare an executive briefing. I'll keep it concise — typically a 10-15 minute presentation covering project status, key achievements, current risks with mitigations, and the recommended path forward. I'll focus on business impact rather than technical detail. Should I plan for 30 minutes to allow Q&A? And could you share your CEO's primary concerns or areas of interest so I can tailor the content accordingly?" },
  { id: 95, title: "Requesting integration with legacy system", clientMessage: "We need the new platform to integrate with our 15-year-old legacy ERP system. The ERP vendor no longer supports it and there's no API. How would you approach this?", suggestedAnswer: "Legacy ERP integration without an API is a common but solvable challenge. The most reliable approach is usually database-level integration or file-based exchange, depending on what the system supports. We could also explore screen scraping as a last resort. I'll need to review the ERP's data structure and available interfaces before recommending the best approach. Can you arrange access to a technical person who knows the ERP system?" },
  { id: 96, title: "Requesting rollback plan", clientMessage: "For every major release going forward, we need a tested rollback plan documented before deployment. Can you formalize this process?", suggestedAnswer: "Absolutely — a rollback plan for every major release is a critical risk management practice. I'll formalize a rollback procedure template covering pre-deployment snapshot, rollback trigger conditions, step-by-step rollback steps, and verification checks. Starting from the next release, this documentation will be reviewed and approved before any major deployment proceeds. I'll have the template ready by end of this week." },
  { id: 97, title: "Requesting cost breakdown", clientMessage: "We'd like a detailed cost breakdown by feature area for the work completed so far. This is to help our finance team allocate development costs internally.", suggestedAnswer: "We can provide that breakdown. I'll compile a cost allocation report showing hours and costs by feature area based on our time tracking data. I'll have it ready by end of week in a format that works for your finance team — could you let me know if they need it in a specific format, such as Excel or a categorized PDF? Also, should I allocate infrastructure and overhead proportionally?" },
  { id: 98, title: "Request for dedicated account manager", clientMessage: "We've been dealing with different points of contact on your side for different issues, which creates confusion and inconsistency. We'd like a dedicated account manager.", suggestedAnswer: "That's a very reasonable request and I hear you. I'm appointing myself as your dedicated account manager effective immediately — all communications, escalations, and decisions will go through me. I'll also schedule a weekly touchpoint call to ensure proactive alignment. I'll send you my direct contact details and calendar link today so you can reach me directly whenever needed." },
  { id: 99, title: "Unresolved recurring bug", clientMessage: "This is the fourth time we've reported the same bug with the file upload function. Each time you say it's fixed, but it keeps coming back. We're losing confidence in your quality process.", suggestedAnswer: "You're right to be frustrated — recurring bugs signal a deeper quality process issue, not just a code problem. I've personally reviewed the fix history and found that each fix has been treating symptoms rather than the root cause. I'm assigning a senior engineer to do a complete rewrite of the file upload module this sprint. I'll also implement automated regression tests specifically for this function so we'll know immediately if it regresses." },
  { id: 100, title: "Requesting open-source policy", clientMessage: "Our legal team wants to know your company's policy on using open-source software in client projects, including how you track licenses and ensure compliance.", suggestedAnswer: "Our open-source policy covers license tracking, compatibility review, and ongoing compliance monitoring. We maintain a software bill of materials for every project and use automated scanning to flag any license changes. I'll send you our complete open-source policy document today. I can also provide a project-specific SBOM listing every open-source component used in your project, if that would help your legal team's review." },
];

export function pickRandom<T>(arr: T[], n: number): T[] {
  const copy = [...arr];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy.slice(0, Math.min(n, copy.length));
}
